// Parse and validate incoming lead data
const body = $input.first().json.body;

// Expected fields from quote tool form
const lead = {
  name: body.name || '',
  phone: body.phone || '',
  email: body.email || '',
  service: body.service || '',
  urgency: body.urgency || 'routine',
  details: body.details || '',
  zipCode: body.zipCode || '',
  preferredTime: body.preferredTime || 'ASAP',
  timestamp: new Date().toISOString(),
  source: body.source || 'website',
  // Client config (which plumbing company)
  clientId: body.clientId || 'default',
  clientName: body.clientName || 'PlumbLead Demo',
  clientPhone: body.clientPhone || '',
  clientEmail: body.clientEmail || ''
};

// Basic validation
const errors = [];
if (!lead.name) errors.push('name required');
if (!lead.phone) errors.push('phone required');
if (!lead.service) errors.push('service required');

if (errors.length > 0) {
  lead.valid = false;
  lead.errors = errors;
} else {
  lead.valid = true;
  // Clean phone number
  lead.phoneClean = lead.phone.replace(/[^0-9+]/g, '');
  if (lead.phoneClean.length === 10) lead.phoneClean = '+1' + lead.phoneClean;
}

// Price ranges per service
const priceRanges = {
  'emergency-leak': { low: 150, mid: 400, high: 800, label: 'Emergency/Leak Repair' },
  'drain-cleaning': { low: 150, mid: 275, high: 400, label: 'Drain Cleaning' },
  'water-heater-tank': { low: 1200, mid: 2000, high: 3500, label: 'Water Heater (Tank)' },
  'water-heater-tankless': { low: 2500, mid: 3500, high: 5000, label: 'Water Heater (Tankless)' },
  'faucet-fixture': { low: 150, mid: 300, high: 500, label: 'Faucet/Fixture Install' },
  'toilet': { low: 150, mid: 300, high: 600, label: 'Toilet Repair/Replace' },
  'garbage-disposal': { low: 200, mid: 350, high: 500, label: 'Garbage Disposal' },
  'sewer-line': { low: 1500, mid: 3500, high: 7000, label: 'Sewer Line Repair' },
  'slab-leak': { low: 2000, mid: 3500, high: 5000, label: 'Slab Leak Repair' },
  'repipe': { low: 4000, mid: 8000, high: 15000, label: 'Whole House Repipe' },
  'gas-line': { low: 300, mid: 700, high: 1500, label: 'Gas Line Work' },
  'water-softener': { low: 800, mid: 1500, high: 3000, label: 'Water Softener Install' },
  'water-test': { low: 0, mid: 0, high: 0, label: 'Free Water Quality Report' },
  'filtration': { low: 300, mid: 1000, high: 2000, label: 'Water Filtration / RO System' },
  'other': { low: 150, mid: 500, high: 2000, label: 'Plumbing Service' }
};

// Attach water quality data if present
if (body.waterReport) {
  lead.waterReport = body.waterReport;
}
lead.language = body.language || 'en';

const pricing = priceRanges[lead.service] || priceRanges['other'];
lead.priceRange = pricing;

return [{ json: lead }];

// Parse AI response and merge with lead data
const lead = $('Parse & Validate Lead').first().json;
let aiResponse;

try {
  const raw = $input.first().json;
  // Handle both formats: {message:{content:[{text}]}} and {content:[{text}]}
  const rawText = raw.message?.content?.[0]?.text || raw.content?.[0]?.text || raw.text || JSON.stringify(raw);
  // Try to extract JSON from the response
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  aiResponse = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
} catch (e) {
  // Fallback response if AI parsing fails
  aiResponse = {
    smsToCustomer: `Hi ${lead.name.split(' ')[0]}! This is ${lead.clientName}. Got your request for ${lead.priceRange.label}. Most jobs like this run $${lead.priceRange.low}-$${lead.priceRange.high}. Can we send a plumber out to give you an exact quote? Reply YES or call us!`,
    leadScore: 5,
    alertToPlumber: `New lead: ${lead.name}, ${lead.priceRange.label}, ${lead.urgency}. Est: $${lead.priceRange.low}-$${lead.priceRange.high}`,
    qualification: 'warm'
  };
}

return [{
  json: {
    ...lead,
    ai: aiResponse
  }
}];

